<?php namespace App\Repositories\Health;use App\Repositories\BaseRepository;use App\Models\Health\Medicine;use Illuminate\Database\Eloquent\Collection;class MedicineRepository extends BaseRepository{    public function __construct(Medicine $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Medicine    {        return $this->query()->where('name', $name)->first();    }    public function findByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function getAvailableMedicines(): Collection    {        return $this->query()->where('stock_quantity', '>', 0)->where('is_active', true)->get();    }    public function getLowStockMedicines(int $threshold = 10): Collection    {        return $this->query()->where('stock_quantity', '<=', $threshold)->where('is_active', true)->get();    }    public function getExpiredMedicines(): Collection    {        return $this->query()->where('expiry_date', '<', now())->get();    }    public function getExpiringSoon(int $days = 30): Collection    {        return $this->query()->where('expiry_date', '>=', now())->where('expiry_date', '<=', now()->addDays($days))->get();    }    public function searchMedicines(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('brand', 'like', "%{$keyword}%")->orWhere('composition', 'like', "%{$keyword}%")->get();    }    public function adjustStock(int $id, int $quantity): bool    {        $medicine = $this->getById($id);        $newStock = $medicine->stock_quantity + $quantity;        return $this->update($id, ['stock_quantity' => max(0, $newStock)]);    }}